def _set_file_permissions(filepath, mode):
    """Set file permissions securely."""
    try:
        if os.path.exists(filepath):
            # Ensure it's not a symlink
            if os.path.islink(filepath):
                raise ValueError(f"Log file must not be a symbolic link: {filepath}")
            os.chmod(filepath, mode)
    except OSError as e:
        # Log to stderr as a fallback since logging may not be fully configured
        import sys
        print(f"WARNING: Could not set permissions on {filepath}: {e}", file=sys.stderr)


