def log_audit_event(event_type, user=None, details=None, success=True):
    """
    Log a structured audit event.

    Args:
        event_type: Type of event (e.g., 'LOGIN', 'ACCESS', 'MODIFY')
        user: Username or identifier associated with the event
        details: Additional details about the event
        success: Whether the action was successful
    """
    audit_logger = get_audit_logger()

    # Sanitize inputs
    safe_event_type = re.sub(r'[^a-zA-Z0-9_]', '', str(event_type)) if event_type else "UNKNOWN"
    safe_user = re.sub(r'[^a-zA-Z0-9_@.\-]', '', str(user)) if user else "SYSTEM"
    safe_details = str(details)[:1024] if details else ""  # Truncate to prevent log flooding
    status = "SUCCESS" if success else "FAILURE"

    audit_logger.info(
        "event=%s | user=%s | status=%s | details=%s",
        safe_event_type,
        safe_user,
        status,
        safe_details,
    )


class SensitiveDataFilter(logging.Filter):
    """
    Filter that redacts sensitive data patterns from log messages.
    Prevents accidental logging of passwords, tokens, SSNs, etc.
    """

    SENSITIVE_PATTERNS = [
        (re.compile(r'(?i)(password|passwd|pwd)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'(?i)(token|api_key|apikey|secret|authorization)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'(?i)(bearer\s+)\S+'), r'\1***REDACTED***'),
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '***SSN-REDACTED***'),
        (re.compile(r'\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b'), '***CC-REDACTED***'),
    ]

    def filter(self, record):
        if isinstance(record.msg, str):
            for pattern, replacement in self.SENSITIVE_PATTERNS:
                record.msg = pattern.sub(replacement, record.msg)
        if record.args:
            if isinstance(record.args, dict):
                record.args = {
                    k: self._redact(v) if isinstance(v, str) else v
                    for k, v in record.args.items()
                }
            elif isinstance(record.args, tuple):
                record.args = tuple(
                    self._redact(v) if isinstance(v, str) else v
                    for v in record.args
                )
        return True

    def _redact(self, text):
        for pattern, replacement in self.SENSITIVE_PATTERNS:
            text = pattern.sub(replacement, text)
        return text


